{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The total opposition to the flow of electric current within a specific component or conductor.",
      "anchor": "The 'friction' encountered by electricity in a specific piece of wire.",
      "misconception": "Believing that only resistors have resistance; in reality, every cable and connection offers some opposition."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "The inherent property of a material that determines how strongly it opposes current flow, regardless of its shape.",
      "anchor": "The 'electrical DNA' of a material like copper or aluminum.",
      "misconception": "Thinking resistivity changes if you make a wire longer; resistivity is constant for the material itself."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (voltage) as current passes through a resistance in a circuit.",
      "anchor": "The drop in water pressure from the start of a long hose to the end.",
      "misconception": "Assuming voltage drop only happens during a fault; it occurs in every functional circuit due to cable resistance."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The unit of measurement for electrical resistance.",
      "anchor": "The 'score' given to how much a component fights the current.",
      "misconception": "Confusing the unit (Ohm) with the property (Resistance) or the material property (Resistivity)."
    },
    {
      "term": "Ohm-metre (Ωm)",
      "simpleDefinition": "The unit of measurement for resistivity.",
      "anchor": "The specific measurement used to compare the quality of different raw materials.",
      "misconception": "Using standard Ohms to describe the resistivity of a material instead of Ohm-metres."
    }
  ],
  "anchorPhrases": [
    "Resistance is the opposition to current flow.",
    "Resistivity is a property of the material itself.",
    "Voltage drop is the loss of electrical pressure.",
    "Every conductor has some resistance.",
    "Resistivity stays the same regardless of the wire's length."
  ],
  "misconceptionTargets": [
    "Resistance and resistivity are interchangeable terms.",
    "Voltage drop only occurs when there is a problem with the circuit.",
    "Changing the size of a conductor changes its resistivity.",
    "Cables have zero resistance because they are conductors."
  ]
}

