    {
      "title": "The Nature of Resistance",
      "basicQuestions": [
        {
          "questionText": "What is the technical term for the total opposition to the flow of electric current?",
          "answerGuidance": [
            "Resistance",
            "Electrical resistance"
          ],
          "hint": "It acts like friction for electricity.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which unit is used to measure the resistance of a conductor?",
          "answerGuidance": [
            "Ohm",
            "Ohms",
            "Ω"
