          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the standard symbol used to represent resistance in electrical notation?",
          "answerGuidance": [
            "R"
          ],
          "hint": "It is the first letter of the word itself.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically incorrect to claim that a standard copper cable in a circuit has zero resistance?",
      "deeperAnswerGuidance": [
