        {
          "questionText": "What term describes the inherent 'specific resistance' of a material regardless of its physical shape?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the material's 'electrical DNA'.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which Greek letter is used as the symbol for resistivity?",
          "answerGuidance": [
            "Rho",
            "ρ"
