          "hint": "It looks like a lowercase 'p'.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "In what unit is the resistivity of a material measured?",
          "answerGuidance": [
            "Ohm-metre",
            "Ohm-metres",
            "Ωm"
          ],
          "hint": "It combines the unit of resistance with a unit of length.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
