      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Consider whether the 'electrical DNA' of the copper changes just because you cut it."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "Which value changes when you increase the length of a specific piece of wire: resistance or resistivity?",
          "answerGuidance": [
            "Resistance"
          ],
          "hint": "One is a property of the object, the other is a property of the material.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP4"
          ]
        },
        {
          "questionText": "Besides resistivity and length, what is the third physical factor that determines a conductor's total resistance?",
          "answerGuidance": [
            "Cross-sectional area",
            "Thickness",
            "Area"
          ],
          "hint": "Think about the 'width' or 'size' of the wire's end.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "If two wires are made of the same material, which property must be identical for both?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the property that describes the raw material itself.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
